// Generic class
class Box<T> {
    private T content;

    public Box(T content) {
        this.content = content;
    }

    public void setContent(T content) {
        this.content = content;
    }

    public T getContent() {
        return content;
    }

    public void display() {
        System.out.println("Content: " + content + " (Type: " + content.getClass().getSimpleName() + ")");
    }
}

// Generic method
class Utility {
    public static <T> void printArray(T[] array) {
        for (T element : array) {
            System.out.print(element + " ");
        }
        System.out.println();
    }

    public static <T> T getMiddle(T[] array) {
        return array[array.length / 2];
    }
}

public class GenericDemo {
    public static void main(String[] args) {
        // Generic class with different types
        Box<String> stringBox = new Box<>("Hello Generics");
        Box<Integer> intBox = new Box<>(100);
        Box<Double> doubleBox = new Box<>(3.14);

        stringBox.display();
        intBox.display();
        doubleBox.display();

        // Generic method
        String[] words = {"Java", "Generics", "are", "powerful"};
        Integer[] numbers = {1, 2, 3, 4, 5, 6, 7};

        System.out.print("Words: ");
        Utility.printArray(words);

        System.out.print("Numbers: ");
        Utility.printArray(numbers);

        System.out.println("Middle word: " + Utility.getMiddle(words));
        System.out.println("Middle number: " + Utility.getMiddle(numbers));
    }
}

import java.util.*;

class Animal {
    void makeSound() { System.out.println("Animal sound"); }
}

class Dog extends Animal {
    void makeSound() { System.out.println("Dog barks"); }
}

class Cat extends Animal {
    void makeSound() { System.out.println("Cat meows"); }
}

public class WildcardDemo {

    // Upper bounded wildcard - extends
    public static void printAnimals(List<? extends Animal> animals) {
        for (Animal animal : animals) {
            animal.makeSound();
        }
    }

    // Lower bounded wildcard - super
    public static void addDogs(List<? super Dog> list) {
        list.add(new Dog());
        list.add(new Dog());
    }

    // Unbounded wildcard
    public static void printList(List<?> list) {
        for (Object obj : list) {
            System.out.println(obj);
        }
    }

    public static void main(String[] args) {
        List<Dog> dogs = Arrays.asList(new Dog(), new Dog());
        List<Cat> cats = Arrays.asList(new Cat(), new Cat());
        List<Animal> animals = new ArrayList<>();

        System.out.println("Dog list:");
        printAnimals(dogs);

        System.out.println("Cat list:");
        printAnimals(cats);

        System.out.println("Animal list:");
        addDogs(animals);  // Animals is superclass of Dog
        printAnimals(animals);

        System.out.println("\nUnbounded wildcard:");
        printList(Arrays.asList(1, "Hello", 3.14));
    }
}

import java.util.*;

public class TypeErasureDemo {
    public static void main(String[] args) {
        // Generic class
        List<String> strings = new ArrayList<>();
        List<Integer> integers = new ArrayList<>();

        // Type erasure means same class at runtime
        System.out.println("strings class: " + strings.getClass().getName());
        System.out.println("integers class: " + integers.getClass().getName());
        System.out.println("Same class? " + strings.getClass().equals(integers.getClass()));

        // Cannot use instanceof with generic type
        // if (strings instanceof List<String>) // Error

        // Generic class example
        Box<String> stringBox = new Box<>("Hello");
        Box<Integer> intBox = new Box<>(100);

        // At runtime, both are Box class
        System.out.println("stringBox class: " + stringBox.getClass().getName());
        System.out.println("intBox class: " + intBox.getClass().getName());
        System.out.println("Same class? " + stringBox.getClass().equals(intBox.getClass()));

        // Bridge methods example
        Parent p = new Child();
        p.print("Hello");  // Calls Child's print

        // Erasure effects
        System.out.println("\nErasure effects:");
        // Cannot overload methods with same erasure
        // void method(List<String> list) {}
        // void method(List<Integer> list) {}  // Error: same erasure
    }
}

class Box<T> {
    private T data;
    Box(T data) { this.data = data; }
    T getData() { return data; }
}

class Parent<T> {
    void print(T value) {
        System.out.println("Parent: " + value);
    }
}

class Child extends Parent<String> {
    @Override
    void print(String value) {
        System.out.println("Child: " + value);
    }
}

import java.util.*;

public class CollectionsDemo {
    public static void main(String[] args) {
        // List
        System.out.println("=== List ===");
        List<String> list = new ArrayList<>();
        list.add("Apple");
        list.add("Banana");
        list.add("Orange");
        list.add("Apple");  // Allows duplicates
        System.out.println("List: " + list);
        System.out.println("Element at index 1: " + list.get(1));

        // Set
        System.out.println("\n=== Set ===");
        Set<Integer> set = new HashSet<>();
        set.add(10);
        set.add(20);
        set.add(30);
        set.add(20);  // Duplicate ignored
        System.out.println("Set: " + set);
        System.out.println("Contains 20? " + set.contains(20));

        // Map
        System.out.println("\n=== Map ===");
        Map<String, Integer> map = new HashMap<>();
        map.put("Apple", 10);
        map.put("Banana", 20);
        map.put("Orange", 30);
        System.out.println("Map: " + map);
        System.out.println("Value for 'Apple': " + map.get("Apple"));
        System.out.println("Keys: " + map.keySet());
        System.out.println("Values: " + map.values());

        // Queue
        System.out.println("\n=== Queue ===");
        Queue<String> queue = new LinkedList<>();
        queue.offer("First");
        queue.offer("Second");
        queue.offer("Third");
        System.out.println("Queue: " + queue);
        System.out.println("Peek: " + queue.peek());
        System.out.println("Poll: " + queue.poll());
        System.out.println("Queue after poll: " + queue);

        // Priority Queue
        System.out.println("\n=== Priority Queue ===");
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        pq.add(5);
        pq.add(1);
        pq.add(3);
        pq.add(2);
        pq.add(4);
        System.out.println("Priority Queue: " + pq);
        while (!pq.isEmpty()) {
            System.out.print(pq.poll() + " ");
        }
        System.out.println();
    }
}

import java.util.*;

public class IteratorDemo {
    public static void main(String[] args) {
        // Basic Iterator
        System.out.println("=== Basic Iterator ===");
        List<String> fruits = new ArrayList<>();
        fruits.add("Apple");
        fruits.add("Banana");
        fruits.add("Orange");
        fruits.add("Grapes");

        Iterator<String> it = fruits.iterator();
        System.out.print("Iterating: ");
        while (it.hasNext()) {
            System.out.print(it.next() + " ");
        }
        System.out.println();

        // Iterator with removal
        System.out.println("\n=== Iterator with Removal ===");
        List<Integer> numbers = new ArrayList<>();
        for (int i = 1; i <= 10; i++) numbers.add(i);
        System.out.println("Original: " + numbers);

        Iterator<Integer> numIt = numbers.iterator();
        while (numIt.hasNext()) {
            int num = numIt.next();
            if (num % 2 == 0) {
                numIt.remove();  // Remove even numbers
            }
        }
        System.out.println("After removing even: " + numbers);

        // ListIterator
        System.out.println("\n=== ListIterator (Bidirectional) ===");
        List<String> names = new ArrayList<>();
        names.add("Alice");
        names.add("Bob");
        names.add("Charlie");

        ListIterator<String> listIt = names.listIterator();
        System.out.print("Forward: ");
        while (listIt.hasNext()) {
            System.out.print(listIt.next() + " ");
        }
        System.out.println();

        System.out.print("Backward: ");
        while (listIt.hasPrevious()) {
            System.out.print(listIt.previous() + " ");
        }
        System.out.println();

        // Enhanced for loop (uses Iterator internally)
        System.out.println("\n=== Enhanced for loop ===");
        for (String name : names) {
            System.out.print(name + " ");
        }
        System.out.println();

        // Custom Iterable implementation
        System.out.println("\n=== Custom Iterable ===");
        MyCollection myCol = new MyCollection();
        for (String item : myCol) {
            System.out.print(item + " ");
        }
        System.out.println();
    }
}

class MyCollection implements Iterable<String> {
    private String[] data = {"A", "B", "C", "D"};

    @Override
    public Iterator<String> iterator() {
        return new Iterator<String>() {
            int index = 0;
            @Override
            public boolean hasNext() {
                return index < data.length;
            }
            @Override
            public String next() {
                return data[index++];
            }
        };
    }
}

import java.util.*;

public class EnhancedForDemo {
    public static void main(String[] args) {
        // Array
        System.out.println("=== Array ===");
        int[] numbers = {10, 20, 30, 40, 50};
        for (int num : numbers) {
            System.out.print(num + " ");
        }
        System.out.println();

        // List
        System.out.println("\n=== List ===");
        List<String> fruits = Arrays.asList("Apple", "Banana", "Orange");
        for (String fruit : fruits) {
            System.out.print(fruit + " ");
        }
        System.out.println();

        // Set
        System.out.println("\n=== Set ===");
        Set<Integer> set = new HashSet<>(Arrays.asList(5, 3, 1, 4, 2));
        for (int num : set) {
            System.out.print(num + " ");
        }
        System.out.println();

        // Map (entry iteration)
        System.out.println("\n=== Map ===");
        Map<String, Integer> map = new HashMap<>();
        map.put("A", 1);
        map.put("B", 2);
        map.put("C", 3);

        for (Map.Entry<String, Integer> entry : map.entrySet()) {
            System.out.println(entry.getKey() + " = " + entry.getValue());
        }

        // Custom object
        System.out.println("\n=== Custom Objects ===");
        List<Person> people = Arrays.asList(
            new Person("Alice", 25),
            new Person("Bob", 30),
            new Person("Charlie", 35)
        );

        for (Person p : people) {
            System.out.println(p.getName() + ": " + p.getAge());
        }
    }
}

