public class WrapperDemo {
    public static void main(String[] args) {
        // Creating wrappers
        Integer intObj = Integer.valueOf(100);
        Double doubleObj = Double.valueOf(3.14);
        Boolean boolObj = Boolean.valueOf(true);
        Character charObj = Character.valueOf('A');

        // Converting String to primitive
        int intVal = Integer.parseInt("123");
        double doubleVal = Double.parseDouble("3.1415");
        boolean boolVal = Boolean.parseBoolean("true");

        System.out.println("Integer object: " + intObj);
        System.out.println("Double object: " + doubleObj);
        System.out.println("Boolean object: " + boolObj);
        System.out.println("Character object: " + charObj);

        System.out.println("\nParsed int: " + intVal);
        System.out.println("Parsed double: " + doubleVal);
        System.out.println("Parsed boolean: " + boolVal);

        // Utility methods
        System.out.println("\nInteger utilities:");
        System.out.println("Min: " + Integer.MIN_VALUE);
        System.out.println("Max: " + Integer.MAX_VALUE);
        System.out.println("Binary: " + Integer.toBinaryString(10));
        System.out.println("Hex: " + Integer.toHexString(255));
        System.out.println("Octal: " + Integer.toOctalString(10));
    }
}

import java.util.*;

public class AutoboxingDemo {
    public static void main(String[] args) {
        // Autoboxing
        int primitiveInt = 100;
        Integer wrapperInt = primitiveInt;  // Autoboxing
        double primitiveDouble = 3.14;
        Double wrapperDouble = primitiveDouble;  // Autoboxing

        System.out.println("Autoboxing:");
        System.out.println("int to Integer: " + wrapperInt);
        System.out.println("double to Double: " + wrapperDouble);

        // Unboxing
        Integer intWrapper = 200;
        int unboxedInt = intWrapper;  // Unboxing
        Double doubleWrapper = 2.718;
        double unboxedDouble = doubleWrapper;  // Unboxing

        System.out.println("\nUnboxing:");
        System.out.println("Integer to int: " + unboxedInt);
        System.out.println("Double to double: " + unboxedDouble);

        // Autoboxing in collections
        List<Integer> numbers = new ArrayList<>();
        numbers.add(10);  // Autoboxing int to Integer
        numbers.add(20);
        numbers.add(30);

        int sum = 0;
        for (int num : numbers) {  // Unboxing Integer to int
            sum += num;
        }
        System.out.println("\nSum: " + sum);

        // Autoboxing in expressions
        Integer a = 5;
        Integer b = 3;
        Integer result = a + b;  // Unboxing, addition, autoboxing
        System.out.println("5 + 3 = " + result);

        // Autoboxing in method calls
        printNumber(42);  // Autoboxing
        printNumber(3.14);  // Autoboxing

        // Potential issues
        Integer nullWrapper = null;
        try {
            int nullInt = nullWrapper;  // NullPointerException
        } catch (NullPointerException e) {
            System.out.println("\nUnboxing null throws NullPointerException");
        }
    }

    static void printNumber(Integer n) {
        System.out.println("Number: " + n);
    }
}
